#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double M, p;
        scanf("%lf %lf", &M, &p);
        double x = 1;
        for (int i = 0; i < M - 1; i++) {
            x = (1 + p * x) / 2;
        }
        printf("%.10f %.10f\n", x * 1e9, (1 - x) * 1e9);
    }
    return 0;
}

