import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            double M = sc.nextDouble();
            double p = sc.nextDouble();
            double x = 1;
            for (int i = 0; i < M - 1; i++) {
                x = (1 + p * x) / 2;
            }
            System.out.printf("%.10f %.10f\n", x * 1e9, (1 - x) * 1e9);
        }
    }
}

